function handleKeyRoomAction(keyRoomId, action, floorIndexHint) {
  const activeRun = getActiveRun();
  if (!activeRun) {
    console.warn("[OPMAP] No active run for key room action");
    return;
  }
  const keyRoomsByFloor = activeRun.keyRoomsByFloor || {};
  let foundFloorIndex = typeof floorIndexHint === "number" && !Number.isNaN(floorIndexHint) ? floorIndexHint : null;
  let keyRoom;
  if (foundFloorIndex !== null) {
    keyRoom = (keyRoomsByFloor[foundFloorIndex] || []).find((kr) => kr.roomNodeId === keyRoomId);
    if (!keyRoom) foundFloorIndex = null;
  }
  if (foundFloorIndex === null) {
    for (const [floorIdxStr, rooms] of Object.entries(keyRoomsByFloor)) {
      const floorIdx = Number(floorIdxStr);
      const found = rooms.find((kr) => kr.roomNodeId === keyRoomId);
      if (found) {
        foundFloorIndex = floorIdx;
        keyRoom = found;
        break;
      }
    }
  }
  if (!keyRoom || foundFloorIndex === null) {
    console.warn("[OPMAP] Key room not found:", keyRoomId);
    return;
  }
  switch (action) {
    case "access":
      Promise.resolve().then(() => (init_KeyRoomManagementScreen(), KeyRoomManagementScreen_exports)).then((m) => {
        m.renderKeyRoomManagementScreen(keyRoomId);
      }).catch(() => {
        const facilityConfig = FACILITY_CONFIG[keyRoom.facility];
        alert(`Key Room: ${facilityConfig.name}

${facilityConfig.description}

Stored Resources:
${Object.entries(keyRoom.storedResources || {}).map(([type, amount]) => `${type}: ${amount}`).join("\n") || "None"}`);
      });
      break;
    case "reinforce":
      Promise.resolve().then(() => (init_KeyRoomReinforceScreen(), KeyRoomReinforceScreen_exports)).then((m) => {
        m.renderKeyRoomReinforceScreen(keyRoomId);
      }).catch(() => {
        alert("Reinforcement system coming soon!");
      });
      break;
    case "field":
      cleanupPanHandlers();
      const fieldMapId = `keyroom_${keyRoomId}`;
      window.map = fieldMapId;
      renderFieldScreen(fieldMapId);
      break;
    default:
      console.warn("[OPMAP] Unknown key room action:", action);
  }
}
