function renderTheaterWindowDock(_theater) {
  const frames = ensureTheaterWindowFrames();
  const dockItems = THEATER_WINDOW_ORDER.filter((key) => {
    if (key === "fortify") {
      return false;
    }
    return frames[key].minimized;
  });
  if (dockItems.length === 0) {
    return "";
  }
  return `
    <div class="theater-window-dock">
      ${dockItems.map((key) => `
        <button
          class="theater-window-dock-item"
          type="button"
          data-theater-window-restore="${key}"
          aria-label="Restore ${THEATER_WINDOW_DEFS[key].title}"
          style="${getTheaterWindowThemeStyle(key)}"
        >
          <span class="theater-window-dock-kicker">${THEATER_WINDOW_DEFS[key].restoreLabel}</span>
          <span class="theater-window-dock-label">${THEATER_WINDOW_DEFS[key].title}</span>
        </button>
      `).join("")}
    </div>
  `;
}
function renderTravelPopup(theater) {
  if (!travelAnimation) {
    return "";
  }
  const fromRoom = theater.rooms[travelAnimation.fromRoomId];
  const toRoom = theater.rooms[travelAnimation.toRoomId];
  if (!fromRoom || !toRoom) {
    return "";
  }
  const popupWidth = Math.min(372, Math.max(280, window.innerWidth - 36));
  const popupHeight = 318;
  const viewportWidth = window.innerWidth;
  const viewportHeight = window.innerHeight;
  const anchorX = Math.round(
    viewportWidth / 2 + mapPanX + (fromRoom.position.x - MAP_WIDTH2 / 2) * mapZoom
  );
  const anchorY = Math.round(
    viewportHeight / 2 + mapPanY + (fromRoom.position.y - MAP_HEIGHT2 / 2) * mapZoom
  );
  const left = clampNumber2(
    anchorX + (anchorX > viewportWidth * 0.62 ? -popupWidth - 72 : 72),
    18,
    viewportWidth - popupWidth - 18
  );
  const top = clampNumber2(
    anchorY - Math.round(popupHeight * 0.46),
    18,
    viewportHeight - popupHeight - 18
  );
  const positionClass = anchorX > viewportWidth * 0.62 ? "theater-travel-popup--left" : "theater-travel-popup--right";
  return `
    <aside
      class="theater-travel-popup ${positionClass}"
      style="${getTheaterWindowThemeStyle("feed")};left:${left}px;top:${top}px;"
      aria-live="polite"
    >
      <div class="theater-travel-popup-header">
        <div class="theater-travel-popup-kicker">SQUAD TRANSIT WINDOW</div>
        <div class="theater-travel-popup-title">IN MOTION</div>
      </div>
      <div class="theater-travel-popup-media-frame">
        <video
          class="theater-travel-popup-video"
          src="${Movement_PT_default}"
          autoplay
          muted
          loop
          playsinline
          preload="auto"
        >
        </video>
      </div>
      <div class="theater-travel-popup-copy">
        Room-to-room movement is in progress. This feed stays active until the squad reaches its destination.
      </div>
      <div class="theater-travel-popup-route">
        <span>${fromRoom.label}</span>
        <span class="theater-travel-popup-route-arrow">-&gt;</span>
        <span>${toRoom.label}</span>
      </div>
    </aside>
  `;
}
function renderPendingBattleConfirmation(theater, destinationRoom) {
  if (!pendingBattleConfirmation || pendingBattleConfirmation.roomId !== destinationRoom.id) {
    return "";
  }
  const previousRoom = theater.rooms[pendingBattleConfirmation.previousRoomId];
  const canFallback = Boolean(previousRoom && previousRoom.id !== destinationRoom.id);
  const positionClass = destinationRoom.position.x > MAP_WIDTH2 * 0.68 ? "theater-room-assault-confirm--left" : "theater-room-assault-confirm--right";
  const selectedSquad = getSelectedTheaterSquad(theater);
  const selectedSquadLabel = getSquadDisplayName(selectedSquad);
  const detailedEnemyIntel = destinationRoom.commsLinked && destinationRoom.commsFlow >= 100;
  return `
    <div class="theater-room-assault-confirm ${positionClass}">
      <div class="theater-room-assault-title">Hostile Contact</div>
      <div class="theater-room-assault-copy">
        Confirm the assault on ${destinationRoom.label}.
      </div>
      <div class="theater-room-assault-route">
        ${previousRoom ? `${previousRoom.label} -&gt; ${destinationRoom.label}` : `${destinationRoom.label} // Direct Engagement`}
      </div>
      <div class="theater-room-assault-briefing">
        <div>${getSquadDisplayIcon(selectedSquad)} ${selectedSquadLabel} // ${selectedSquad?.bwAvailable ?? 0}/${selectedSquad?.bwRequired ?? 0} BW</div>
        ${detailedEnemyIntel ? `<div>Enemy Intel uplink stable // detailed telemetry available in battle.</div>` : ""}
      </div>
      <div class="theater-room-assault-actions">
        <button class="theater-room-assault-btn theater-room-assault-btn--primary" type="button" id="theaterConfirmBattleBtn">
          Start Battle
        </button>
        <button class="theater-room-assault-btn" type="button" id="theaterFallbackBtn" ${canFallback ? "" : "disabled"}>
          Go Back
        </button>
        ${destinationRoom.secured && (destinationRoom.underThreat || destinationRoom.damaged) ? `
          <button class="theater-room-assault-btn" type="button" id="theaterRefuseDefenseBtn">
            Refuse Defense
          </button>
        ` : ""}
      </div>
    </div>
  `;
}
function renderCompletionCallout(theater, completion, canDescend) {
  const completionRoom = theater.rooms[completion.roomId];
  if (!completionRoom || !isRoomVisible2(completionRoom)) {
    return "";
  }
  const positionClass = completionRoom.position.x > MAP_WIDTH2 * 0.68 ? "theater-room-completion-popup--left" : "theater-room-completion-popup--right";
  const atlasBackedOperation = isOpsTerminalAtlasOperation(getGameState().operation);
  return `
    <div
      class="theater-room-completion-popup ${positionClass}"
      data-theater-room-completion-popup="true"
    >
      <div class="theater-room-completion-title">Objective Secured</div>
      <div class="theater-room-completion-room">${completionRoom.label}</div>
      <div class="theater-room-completion-copy">
        ${canDescend ? "Floor objective complete. Rewards are already secured. Remain in theater as long as you want, then descend when ready." : atlasBackedOperation ? "Operation objective complete. Rewards are already secured. Remain in theater as long as you want, then return to A.T.L.A.S. when ready." : "Operation objective complete. Rewards are already secured. Remain in theater as long as you want, then return to Base Camp when ready."}
      </div>
      <div class="theater-completion-recap">
        ${completion.recapLines.map((line) => `<div class="theater-completion-line">${line}</div>`).join("")}
      </div>
      <div class="theater-completion-reward-grid">
        <div class="theater-completion-reward-item"><span>Wad</span><strong>+${completion.reward.wad}</strong></div>
        <div class="theater-completion-reward-item"><span>Metal Scrap</span><strong>+${completion.reward.metalScrap}</strong></div>
        <div class="theater-completion-reward-item"><span>Wood</span><strong>+${completion.reward.wood}</strong></div>
        <div class="theater-completion-reward-item"><span>Chaos Shards</span><strong>+${completion.reward.chaosShards}</strong></div>
        <div class="theater-completion-reward-item"><span>Steam Components</span><strong>+${completion.reward.steamComponents}</strong></div>
      </div>
      <div class="theater-room-completion-actions">
        ${canDescend ? `
            <button class="theater-room-assault-btn theater-room-assault-btn--primary" type="button" id="theaterCompletionAdvanceBtn">
              Descend To Next Floor
            </button>
          ` : `
            <button class="theater-room-assault-btn theater-room-assault-btn--primary" type="button" id="theaterCompletionReturnBtn">
              ${atlasBackedOperation ? "Return To A.T.L.A.S." : "Return To Base Camp"}
            </button>
          `}
      </div>
      <div class="theater-room-completion-note">
        Leave this window alone if you want to keep operating before exit.
      </div>
    </div>
  `;
}
function renderCompletionPopupForRoom(theater, room, canDescend) {
  const completion = theater.completion;
  if (!theater.objectiveComplete || !completion || completion.roomId !== room.id) {
    return "";
  }
  return renderCompletionCallout(theater, completion, canDescend);
}
